package com.aadil.jobtracker.security;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.PostMapping;import org.springframework.web.bind.annotation.RequestBody;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;@RestController@RequestMapping("/api/auth/**")public class AuthenticationController {    private final AuthenticationService service;    public AuthenticationController(AuthenticationService service) {        this.service = service;    }    @PostMapping("/regsiter")    public ResponseEntity<String> register (@RequestBody RequestRegisterDTO register){        service.register(register);        return ResponseEntity.ok("User Registered Successfully");    }    @PostMapping("/login")    public void login (@RequestBody LoginRequestDTO login){       service.login(login);    }}